ValidationRule.errorConditionFormula:
OR(
/* if approved and date not there*/
AND(
ISPICKVAL( Application_Status__c , 'Approved'),
ISBLANK( Disbursement_Date__c )
),
/* if not approved and date is present */
AND(
NOT(ISPICKVAL(Application_Status__c , 'Approved')),
NOT(ISBLANK(Disbursement_Date__c ))
)
)
